using House_renting_system_Project.Models;
using Microsoft.AspNetCore.Mvc;

namespace House_renting_system_Project.Controllers
{
    public class HouseController : Controller
    {
        private List<HousesViewModel> houses = new List<HousesViewModel>()
        {
            new HousesViewModel()
            {
                Id= 1,
                Name = "Beach house",
                Address = "Miami, Florida",
                ImageUrl = @"data:image/jpeg;base64,"

            },
            new HousesViewModel()
            {
                Id = 2,
                Name = "Mountin house",
                Address = "Rila, Bulgaria",
                ImageUrl = @"data:image/jpeg;base64,"
            },
            new HousesViewModel()
            {
                Id = 3,
                Name = "Urban house",
                Address = "Lulin, Sofia",
                ImageUrl = @"https://encrypted-tbn0.gstatic.com/images?q=tbn:ANd9GcSZ2NEVJXC4wg72ILEs5xaV6lFbdl5H_cHQvg&s"
            }
        };
        public IActionResult AllHouses()
        {
            return View(houses);
        }

        public IActionResult Details(int Id)
        {
            var dwefdw = houses.FirstOrDefault(h => h.Id == Id);
            return View(dwefdw);
        }

    }
